import React, { useState } from 'react';
import axios from '../api/axiosConfig';

function SubmitComplaintPage({ user }) {
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [imageUrl, setImageUrl] = useState('');
  const [category, setCategory] = useState('electrical');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  const handleSubmit = async (event) => {
    event.preventDefault();
    setError('');
    setSuccess('');
    if (!user) {
      setError('Please login to submit a complaint');
      return;
    }

    setLoading(true);
    try {
      await axios.post('/complaints', { title, description, category });
      setSuccess('Complaint submitted successfully');
      setTitle('');
      setDescription('');
      setCategory('electrical');
    } catch (err) {
      setError(err.response?.data?.message || 'Unable to submit complaint');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="card">
      <h2>Submit Complaint</h2>
      <form onSubmit={handleSubmit}>
        <label>Title</label>
        <input value={title} onChange={(e) => setTitle(e.target.value)} placeholder="Complaint title" />

        <label>Description</label>
        <textarea
          value={description}
          onChange={(e) => setDescription(e.target.value)}
          placeholder="Describe the issue"
          rows="5"
        />

        <label>Image URL (optional)</label>
        <input
          value={imageUrl}
          onChange={(e) => setImageUrl(e.target.value)}
          placeholder="Paste an image link"
        />

        <label>Category</label>
        <select value={category} onChange={(e) => setCategory(e.target.value)}>
          <option value="electrical">Electrical</option>
          <option value="water">Water</option>
          <option value="internet">Internet</option>
          <option value="cleaning">Cleaning</option>
          <option value="others">Others</option>
        </select>

        {error && <div className="error-box">{error}</div>}
        {success && <div className="success-box">{success}</div>}
        <button type="submit" disabled={loading}>
          {loading ? 'Submitting...' : 'Submit Complaint'}
        </button>
      </form>
    </div>
  );
}

export default SubmitComplaintPage;
